const gh = $input.first().json;
let jobs = [];
try {
  const db    = JSON.parse(Buffer.from(gh.content, 'base64').toString('utf-8'));
  const today = new Date().toISOString().slice(0, 10);
  jobs = (db.jobs || [])
    .filter(j => j.date_found && j.date_found.startsWith(today) && j.job_url)
    .sort((a, b) => (b.relevance_score || 0) - (a.relevance_score || 0))
    .slice(0, 5);
  console.log('Top-5 for ' + today + ': ' + jobs.length + ' jobs');
} catch(e) { console.log('Load error:', e.message); }
if (!jobs.length) { console.log('No new jobs today — Agent 2 exits.'); return []; }
return jobs.map(j => ({ json: j }));

const job = $input.first().json;
return [{ json: {
  groq_request: {
    model: 'openai/gpt-oss-120b', temperature: 0.2, max_tokens: 350,
    messages: [
      { role: 'system', content: 'Extract ATS keywords. Return ONLY a JSON object, no markdown.' },
      { role: 'user',   content: 'Job: "' + job.title + '" at ' + job.company +
        ' (' + job.location + ', ' + job.job_type + ')\n' +
        'Return: {"required":["str"],"nice_to_have":["str"],"concepts":["str"],"level":"intern|junior"}' }
    ]
  },
  _pt: job
} }];

const all      = $input.all();
const groqItem = all.find(i => i.json.choices !== undefined);
const ptItem   = all.find(i => i.json._pt    !== undefined);
const job      = ptItem ? ptItem.json._pt : {};

const SKILLS = ['Python','PyTorch','TensorFlow','Scikit-learn','Flask','FastAPI','NLP','NLTK','SpaCy','Transformer','LLM','Large Language Model','Flutter','Dart','Pandas','NumPy','Machine Learning','Deep Learning','Computer Vision','Hugging Face','REST API','Docker','Git'];
let kw = { required: [], nice_to_have: [], concepts: [], level: 'junior' };
if (groqItem) {
  try {
    kw = JSON.parse(groqItem.json.choices[0].message.content
      .replace(/```json|```/g, '').trim());
  } catch(e) { console.log('KW parse fallback for "' + job.title + '"'); }
}

const allReq  = [...(kw.required || []), ...(kw.concepts || [])];
const matched = allReq.filter(k =>
  SKILLS.some(s => s.toLowerCase() === k.toLowerCase() ||
                   k.toLowerCase().includes(s.toLowerCase())));
const missing = (kw.required || []).filter(k =>
  !SKILLS.some(s => s.toLowerCase() === k.toLowerCase()));

return [{ json: {
  groq_request: {
    model: 'openai/gpt-oss-120b', temperature: 0.5, max_tokens: 1500,
    messages: [
      { role: 'system',
        content: 'Expert ATS resume optimizer for AI/ML roles. 100% truthful — never fabricate. Output clean plain text, no markdown.' },
      { role: 'user',
        content: 'Optimize resume for: "' + job.title + '" at ' + job.company + '\n' +
          'Emphasize naturally: ' + matched.join(', ') + '\n' +
          'Candidate gaps (do NOT invent): ' + (missing.join(', ') || 'none') + '\n\n' +
          'CANDIDATE FACTS (immutable):\n' +
          '[CANDIDATE NAME] | [CANDIDATE_EMAIL@EXAMPLE.COM] | [PHONE NUMBER]\n' +
          'GitHub: github.com/AbhinaySucharith | Guntur, Andhra Pradesh\n' +
          'B.Tech AI & Machine Learning, VVIT Guntur | CGPA 8.35 | Graduating Sep 2026\n\n' +
          'PROJECTS:\n' +
          '1. EMERALD — ~10M param GPT transformer, PyTorch, custom BPE tokenizer, ' +
            'Wikipedia corpus, autoregressive training (grad clip, LR sched, checkpointing), ' +
            'Flask inference server with real-time text generation\n' +
          '2. Fake News Detection — TensorFlow + NLTK/SpaCy pipeline, TF-IDF + semantic ' +
            'features, class-imbalance handling, Flask REST API, precision/recall/F1 eval\n' +
          '3. AI Crop Prediction — Scikit-learn multi-class (22 crops, soil/env params), ' +
            'FastAPI backend, cross-platform Flutter mobile app with full UI\n\n' +
          'SKILLS: Python, PyTorch, TensorFlow, Scikit-learn, Flask, FastAPI, NLTK, SpaCy, ' +
            'Pandas, NumPy, Flutter, Dart, JavaScript, HTML, CSS\n' +
          'CERTS: NPTEL Elite — Introduction to Large Language Models\n' +
          'LEADERSHIP: ACM Membership Chair VVIT | SIH 2025 Internal Selection\n\n' +
          'OUTPUT — plain text, ATS-compatible sections:\n' +
          '[HEADER] [PROFILE SUMMARY 60-70 words] [TECHNICAL SKILLS] ' +
          '[PROJECTS reordered by relevance] [CERTIFICATIONS & LEADERSHIP] [EDUCATION]' }
    ]
  },
  _pt: { job, matched_keywords: matched, missing_keywords: missing }
} }];

const all      = $input.all();
const groqItem = all.find(i => i.json.choices !== undefined);
const ptItem   = all.find(i => i.json._pt    !== undefined);
const pt       = ptItem ? ptItem.json._pt : {};
const job      = pt.job || {};

let resume_text = '';
if (groqItem) {
  try { resume_text = groqItem.json.choices[0].message.content; }
  catch(e) { console.log('Resume extract error'); }
}

return [{ json: {
  groq_request: {
    model: 'openai/gpt-oss-120b', temperature: 0.3, max_tokens: 500,
    messages: [
      { role: 'system', content: 'ATS scoring expert. Return ONLY a JSON object, no markdown.' },
      { role: 'user',
        content: 'Score resume-job fit for "' + job.title + '" at ' + job.company + '.\n' +
          'Matched: ' + (pt.matched_keywords || []).join(', ') + '\n' +
          'Missing: ' + (pt.missing_keywords || []).join(', ') + '\n' +
          'Candidate: B.Tech AI&ML, EMERALD (10M GPT PyTorch), NLP pipeline (TF+Flask), Flutter+FastAPI.\n' +
          'Return JSON: {"ats_score":number,"breakdown":{"keyword_match":number,"relevance":number,' +
          '"skills":number,"projects":number},"strengths":["str"],"improvements":["str"],' +
          '"hiring_potential":number,"recommendation":"strong_fit|good_fit|moderate_fit"}' }
    ]
  },
  _pt: { job, matched_keywords: pt.matched_keywords,
         missing_keywords: pt.missing_keywords, resume_text }
} }];

const all      = $input.all();
const groqItem = all.find(i => i.json.choices !== undefined);
const ptItem   = all.find(i => i.json._pt    !== undefined);
const pt       = ptItem ? ptItem.json._pt : {};
const job      = pt.job || {};

let ats = { ats_score: 65, breakdown: {}, strengths: [], improvements: [],
            hiring_potential: 60, recommendation: 'good_fit' };
if (groqItem) {
  try {
    ats = JSON.parse(groqItem.json.choices[0].message.content
      .replace(/```json|```/g, '').trim());
  } catch(e) { console.log('ATS parse fallback for "' + job.title + '"'); }
}

const jobId = job.job_id || 'unknown';
// FIX: bare filename — path prefix added in httpRequest URL expression
const resumeFilename = jobId + '_resume.txt';
const atsFilename    = jobId + '_ats_report.json';

const atsReport = {
  job_id: jobId, job_title: job.title || '', company: job.company || '',
  job_url: job.job_url || '', ats_score: ats.ats_score || 65,
  breakdown: ats.breakdown || {}, strengths: ats.strengths || [],
  improvements: ats.improvements || [], hiring_potential: ats.hiring_potential || 60,
  recommendation: ats.recommendation || 'good_fit',
  matched_keywords: pt.matched_keywords || [],
  missing_keywords: pt.missing_keywords || [],
  generated_at: new Date().toISOString()
};

return [{ json: {
  resume_text:     pt.resume_text || '',
  resume_filename: resumeFilename,
  ats_report:      atsReport,
  ats_filename:    atsFilename,
  job_id:    jobId,        job_title: job.title,
  company:   job.company,  ats_score: ats.ats_score || 65,
  recommendation: ats.recommendation || 'good_fit'
} }];

const d = $input.first().json;
return [{ json: {
  github_payload: {
    message: 'auto: resume for ' + d.company + ' [' + d.job_id + ']',
    content: Buffer.from(d.resume_text || '').toString('base64'),
    branch: 'state'
  },
  filename:   d.resume_filename,
  job_id:     d.job_id,
  job_title:  d.job_title,
  company:    d.company,
  ats_score:  d.ats_score,
  recommendation: d.recommendation,
  ats_report:     d.ats_report,
  ats_filename:   d.ats_filename
} }];

const d = $input.first().json;
return [{ json: {
  github_payload: {
    message: 'auto: ATS report for ' + d.company + ' [' + d.job_id + ']',
    content: Buffer.from(JSON.stringify(d.ats_report, null, 2)).toString('base64'),
    branch: 'state'
  },
  filename:      d.ats_filename,
  job_id:        d.job_id,
  job_title:     d.job_title,
  company:       d.company,
  ats_score:     d.ats_score,
  recommendation: d.recommendation
} }];

const all = $input.all();
const d   = all[0] ? all[0].json : {};
console.log('=== AGENT 2 COMPLETE ===');
console.log('Job: "' + d.job_title + '" @ ' + d.company);
console.log('ATS: ' + d.ats_score + ' | ' + d.recommendation);
console.log('Resume path:     data/resumes/' + d.job_id + '_resume.txt');
console.log('ATS report path: data/ats_reports/' + d.job_id + '_ats_report.json');
return [{ json: { status: 'success', job_id: d.job_id,
  job_title: d.job_title, company: d.company, ats_score: d.ats_score,
  completed_at: new Date().toISOString() } }];
